#include<cstdio>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
#define grep(b,c) for(int c=head[b];c;c=nxt[c])
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
inline bool Get(){char ch;do ch=getchar();while(ch!='Q'&&ch!='C');return ch=='C';}
inline void pt(const int &p){if(p>9)pt(p/10);putchar(p%10+'0');}
inline void print(const int &p,const char &ch='\n'){pt(p<0?putchar('-'),-p:p);putchar(ch);}
template <typename T> inline void Swap(T&x,T&y){T tmp=x;x=y;y=tmp;}
const int N=1e5+10;struct Tri
{
	int sm,lc,rc;inline Tri(const int &x=0,const int &y=0,const int &z=0){sm=x;lc=y;rc=z;}
	inline Tri operator + (const Tri &x)const{return Tri(sm+x.sm-(rc==x.lc),lc,x.rc);} 
};
int head[N],des[N<<1],nxt[N<<1],cgt,dl[N],mxs[N],dep[N],fa[N],siz[N],cnt,top[N],lc[N<<2],rc[N<<2],tg[N<<2],sm[N<<2],n,a[N],P[N];
inline void ins(const int &x,const int &y){nxt[++cgt]=head[x];des[head[x]=cgt]=y;nxt[++cgt]=head[y];des[head[y]=cgt]=x;}
inline void dfs0(const int &u=1,const int &f=0)
{
	dep[u]=dep[fa[u]=f]+1;siz[u]=1;int mx=0;
	grep(u,i)if(des[i]!=f){int v=des[i];dfs0(v,u);siz[u]+=siz[v];mx<siz[v]?mx=siz[mxs[u]=v]:0;}
}
inline void dfs1(const int &u=1,const int &fa=0,const int &tp=1)
{
	top[u]=tp;P[dl[u]=++cnt]=u;if(mxs[u])dfs1(mxs[u],u,tp);
	grep(u,i)if(des[i]!=fa&&des[i]!=mxs[u])dfs1(des[i],u,des[i]);
}
inline void pushdown(const int &p)
{
	if(!tg[p])return;const int &l=p<<1,&r=l|1,c=tg[p];tg[p]=0;
	tg[l]=tg[r]=lc[l]=rc[l]=lc[r]=rc[r]=c; sm[l]=sm[r]=1;
}
inline void update(const int &p)
{
	const int &l=p<<1,&r=l|1;
	sm[p]=sm[l]+sm[r]-(rc[l]==lc[r]);lc[p]=lc[l];rc[p]=rc[r];
}
inline void build(const int &l=1,const int &r=n,const int &cur=1)
{
	if(l==r)return lc[cur]=rc[cur]=a[P[l]],sm[cur]=1,void();
	int mid((l+r)>>1);build(l,mid,cur<<1);build(mid+1,r,cur<<1|1);update(cur);
}
inline void mdy(const int &ql,const int &qr,const int &c,const int &l=1,const int &r=n,const int &cur=1)
{
	if(ql<=l&&r<=qr){sm[cur]=1;lc[cur]=rc[cur]=tg[cur]=c;return;} int mid=(l+r)>>1;pushdown(cur);
	if(ql<=mid)mdy(ql,qr,c,l,mid,cur<<1);if(qr>mid)mdy(ql,qr,c,mid+1,r,cur<<1|1); update(cur);
}
inline Tri qry(const int &ql,const int &qr,const int &l=1,const int &r=n,const int &cur=1)
{
	if(ql<=l&&r<=qr)return Tri(sm[cur],lc[cur],rc[cur]);int mid=(l+r)>>1;Tri res;pushdown(cur);
	if(qr<=mid)res=qry(ql,qr,l,mid,cur<<1);else if(ql>mid)res=qry(ql,qr,mid+1,r,cur<<1|1);
	else  res=qry(ql,qr,l,mid,cur<<1)+qry(ql,qr,mid+1,r,cur<<1|1);update(cur);return res;
}
inline int Cnt(int u,int v)
{
	Tri tu,tv;while(top[u]!=top[v])
	{
		if(dep[top[u]]<dep[top[v]])Swap(u,v),Swap(tu,tv);
		tu=qry(dl[top[u]],dl[u])+tu;u=fa[top[u]];
	}
	if(dep[u]<dep[v])Swap(u,v),Swap(tu,tv); Tri tmp=qry(dl[v],dl[u]);
	Swap(tv.lc,tv.rc); return (tv+tmp+tu).sm;
}
inline void Mdy(const int &c,int u,int v)
{
	while(top[u]!=top[v])
	{
		if(dep[top[u]]<dep[top[v]])Swap(u,v);
		mdy(dl[top[u]],dl[u],c);u=fa[top[u]];
	}
	if(dep[u]<dep[v])Swap(u,v);mdy(dl[v],dl[u],c);
}
int main()
{
	n=read();int Q=read();rep(1,n,i)a[i]=read();rep(2,n,i)ins(read(),read());dfs0();dfs1();build();
	while(Q--)Get()?Mdy(read(),read(),read()):print(Cnt(read(),read()));return 0;
}
